const crypto = require('crypto');
const body = $input.first().json.body || $input.first().json;
const email = (body.email||'').trim().toLowerCase();
const password = body.password||'';
if (!email.includes('@') || password.length < 6) { return [{json:{ok:false,error:'invalid email or password<6'}}]; }
const salt = crypto.randomBytes(16).toString('hex');
const hash = crypto.pbkdf2Sync(password, salt, 100000, 32, 'sha256').toString('hex');
const token = crypto.randomBytes(32).toString('hex');
return [{ json: { ok:true, email, salt, hash, token } }];

const rows = $input.all().map(i=>i.json);
if (!rows.length) return [{ json: { ok:false, error:'email already exists' } }];
return [{ json: { ok:true, email: rows[0].email, token: rows[0].token } }];

const body = $input.first().json.body || $input.first().json;
const email = (body.email||'').trim().toLowerCase();
const password = body.password||'';
return [{ json: { email, password } }];

const crypto = require('crypto');
const rows = $input.all().map(i=>i.json);
const inp = $('Prep').first().json;
if (!rows.length) return [{ json: { ok:false, error:'invalid credentials' } }];
const u = rows[0];
const calc = crypto.pbkdf2Sync(inp.password, u.salt, 100000, 32, 'sha256').toString('hex');
if (calc !== u.password_hash) return [{ json: { ok:false, error:'invalid credentials' } }];
const token = crypto.randomBytes(32).toString('hex');
return [{ json: { ok:true, id:u.id, email:u.email, token } }];

const j = $('Verify').first().json;
if (!j.ok) return [{ json: { ok:false, error: j.error } }];
return [{ json: { ok:true, email:j.email, token:j.token } }];
